sql:
SELECT type, AVG(area) AS average_area
FROM quadrats
GROUP BY type;

external_knowledge:
- 'high quantities' refers to total abundance greater than 50; 
- 'active stations' refers to stations with a status of 'active'; 
- 'permanent quadrats' refers to quadrats with a type of 'permanent'.

sql:
SELECT COUNT(*) AS collection_count
FROM taxon_collections
WHERE taxon_id = 1 AND abundance > 10;

SELECT station_name
FROM stations
ORDER BY station_name;

SELECT abundance
FROM taxon_collections
WHERE taxon_id = 0;
